import collections

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.size = [1] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.size[root_i] < self.size[root_j]:
                self.parent[root_i] = root_j
                self.size[root_j] += self.size[root_i]
            else:
                self.parent[root_j] = root_i
                self.size[root_i] += self.size[root_j]
            return True
        return False

def smallest_string_with_swaps(s: str, pairs: list[list[int]]) -> str:
    n = len(s)
    uf = UnionFind(n)

    for i, j in pairs:
        uf.union(i, j)

    components = collections.defaultdict(lambda: {'indices': [], 'chars': []})
    for i in range(n):
        root = uf.find(i)
        components[root]['indices'].append(i)
        components[root]['chars'].append(s[i])

    result = [''] * n
    for root in components:
        indices = components[root]['indices']
        chars = components[root]['chars']

        indices.sort()
        chars.sort()

        for k in range(len(indices)):
            result[indices[k]] = chars[k]

    return "".join(result)
